PREFIX edai: <http://example.org/edai/>
SELECT (COUNT(?p) AS ?count) WHERE {
  ?p a edai:Person .
}

PREFIX edai: <http://example.org/edai/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?uni ?name WHERE {
  ?uni a edai:University .
  ?uni rdfs:label ?name .
}

PREFIX edai: <http://example.org/edai/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?org ?orgName WHERE {
  ?person edai:locatedIn ?loc .
  ?loc rdfs:label "United States" .
}

SELECT ?country WHERE {
  ?subject wdt:P31 wd:Q110 .
  ?country wdt:P279 ?countryLabel .
  SERVICE wikibase:label { bd:label ?countryLabel . }
}

PREFIX edai: <http://example.org/edai/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT (COUNT(?s) AS ?count) WHERE {
  ?s edai:coAuthorWith ?o .
}
